const lead = $input.all()[0].json;
const customerName = lead.customerName || 'there';
const fromAddr = lead.fromAddress || 'your current address';
const toAddr = lead.toAddress || 'your new home';
const movingDate = lead.movingDate || 'your chosen date';

const html = `
<!DOCTYPE html>
<html>
<body style="background: linear-gradient(135deg, #0f0c29, #302b63, #24243e); min-height: 100vh; padding: 40px 20px; font-family: -apple-system, sans-serif;">
  <div style="max-width: 600px; margin: 0 auto; background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.12); border-radius: 24px; padding: 48px;">
    <h1 style="color: white; font-size: 28px; text-align: center;">We've Received Your Enquiry!</h1>
    <p style="color: rgba(255,255,255,0.7); font-size: 16px; text-align: center;">Hi ${customerName}, thank you for reaching out. We'll get back to you within 2 hours.</p>
    <div style="background: rgba(255,255,255,0.06); border-radius: 12px; padding: 20px; margin: 24px 0;">
      <p style="color: rgba(255,255,255,0.5); font-size: 12px; text-transform: uppercase; letter-spacing: 1px;">Moving Details</p>
      <p style="color: white;">📍 From: ${fromAddr}</p>
      <p style="color: white;">🏠 To: ${toAddr}</p>
      <p style="color: white;">📅 Date: ${movingDate}</p>
    </div>
  </div>
</body>
</html>`;

return [{ json: { ...lead, emailHtml: html } }];
